Сортировка пузырьком (Bubble Sort) - простой алгоритм сортировки, который последовательно сравнивает пары соседних элементов и меняет их местами, если они стоят в неправильном порядке. Повторяется это до тех пор, пока массив не будет отсортирован.

Вот пример реализации сортировки пузырьком на Java:
```java
public class BubbleSort {
    public static void bubbleSort(int[] arr) {
        int n = arr.length;
        boolean swapped;
        for (int i = 0; i < n - 1; i++) {
            swapped = false;
            for (int j = 0; j < n - 1 - i; j++) {
                if (arr[j] > arr[j + 1]) {
                    // Swap arr[j] and arr[j+1]
                    int temp = arr[j];
                    arr[j] = arr[j + 1];
                    arr[j + 1] = temp;
                    swapped = true;
                }
            }
            // If no two elements were swapped in the inner loop, then the array is already sorted
            if (!swapped) {
                break;
            }
        }
    }

    public static void main(String[] args) {
        int[] arr = {64, 34, 25, 12, 22, 11, 90};
        bubbleSort(arr);
        System.out.println("Sorted array:");
        for (int i : arr) {
            System.out.print(i + " ");
        }
    }
}
```

Этот код сначала создает массив arr, который нужно отсортировать, затем вызывает метод bubbleSort для сортировки массива. В конце выводится отсортированный массив.

Обратите внимание, что сортировка пузырьком не является самым эффективным способом сортировки массива из-за своей квадратичной временной сложности в худшем случае. Однако для небольших массивов или в учебных целях сортировка пузырьком может быть полезной.

```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.9.1;

contract MazuriGameFi {
    string public name = "Mazuri GameFi";
    string public symbol = "MZR";
    uint256 public maxSupply = 100000000;
    uint256 public totalSupply = 100000000;
    address public owner;

    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);

    constructor() {
        owner = msg.sender;
        balanceOf[owner] = totalSupply;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can call this function");
        _;
    }

    function transfer(address to, uint256 value) public returns (bool) {
        require(balanceOf[msg.sender] >= value, "Not enough tokens");

        balanceOf[msg.sender] -= value;
        balanceOf[to] += value;

        emit Transfer(msg.sender, to, value);
        return true;
    }

    function approve(address spender, uint256 value) public returns (bool) {
        allowance[msg.sender][spender] = value;
        emit Approval(msg.sender, spender, value);
        return true;
    }

    function transferFrom(address from, address to, uint256 value) public returns (bool) {
        require(balanceOf[from] >= value, "Not enough tokens");
        require(allowance[from][msg.sender] >= value, "Not allowed to spend this amount");

        balanceOf[from] -= value;
        balanceOf[to] += value;
        allowance[from][msg.sender] -= value;

        emit Transfer(from, to, value);
        return true;
    }
}
```

