```cpp
#include <iostream>
#include <vector>
#include <cmath>

struct Student {
    int age;
    int height;
    int grade;
};

std::vector<Student> students;

void addStudent(int age, int height, int grade) {
    Student newStudent = {age, height, grade};
    students.push_back(newStudent);
}

std::vector<int> uniqueStudents() {
    std::vector<int> uniqueIndices;
    for (int i = 0; i < students.size(); i++) {
        int uniqueCount = 0;
        for (int j = 0; j < 3; j++) {
            float average = 0.0;
            for (int k = 0; k < 3; k++) {
                average += students[i].age;
                average += students[i].height;
                average += students[i].grade;
            }
            average /= 3.0;

            if (std::abs(average - students[i].age) < 1.0 || 
                std::abs(average - students[i].height) < 1.0 || 
                std::abs(average - students[i].grade) < 1.0) {
                uniqueCount++;
            }
        }

        if (uniqueCount == 3) {
            uniqueIndices.push_back(i);
        }
    }

    return uniqueIndices;
}

std::vector<int> averageStudents() {
    std::vector<int> averageIndices;
    for (int i = 0; i < students.size(); i++) {
        int averageCount = 0;
        for (int j = 0; j < 3; j++) {
            float average = 0.0;
            for (int k = 0; k < 3; k++) {
                average += students[i].age;
                average += students[i].height;
                average += students[i].grade;
            }
            average /= 3.0;

            if (std::abs(average - students[i].age) < 1.0 || 
                std::abs(average - students[i].height) < 1.0 || 
                std::abs(average - students[i].grade) < 1.0) {
                averageCount++;
            }
        }

        if (averageCount > 1) {
            averageIndices.push_back(i);
        }
    }

    return averageIndices;
}

int main() {
    addStudent(20, 170, 85);
    addStudent(18, 165, 90);
    addStudent(22, 175, 80);

    std::vector<int> unique = uniqueStudents();
    std::cout << "Unique students:";
    for (int index : unique) {
        std::cout << " " << index;
    }
    std::cout << std::endl;

    std::vector<int> average = averageStudents();
    std::cout << "Average students:";
    for (int index : average) {
        std::cout << " " << index;
    }
    std::cout << std::endl;

    return 0;
}
```

