Вот пример программы на C, которая читает таблицу маршрутизации через netlink и выводит ее на консоль:

```c
#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <unistd.h>
#include <arpa/inet.h>
#include <linux/netlink.h>
#include <linux/rtnetlink.h>
#include <sys/socket.h>

#define BUFSIZE 8192

int main() {
    struct sockaddr_nl addr;
    int sock = socket(AF_NETLINK, SOCK_RAW, NETLINK_ROUTE);
    if (sock < 0) {
        perror("socket");
        exit(EXIT_FAILURE);
    }

    memset(&addr, 0, sizeof(addr));
    addr.nl_family = AF_NETLINK;
    addr.nl_groups = RTMGRP_IPV4_ROUTE;

    if (bind(sock, (struct sockaddr*)&addr, sizeof(addr)) < 0) {
        perror("bind");
        close(sock);
        exit(EXIT_FAILURE);
    }

    while (1) {
        char buf[BUFSIZE];
        struct nlmsghdr *nh;
        struct rtmsg *rtm;
        struct rtattr *attr;
        int len;

        len = recv(sock, buf, sizeof(buf), 0);
        for (nh = (struct nlmsghdr *)buf; NLMSG_OK(nh, len); nh = NLMSG_NEXT(nh, len)) {
            if (nh->nlmsg_type == NLMSG_DONE) {
                break;
            }

            rtm = (struct rtmsg *)NLMSG_DATA(nh);
            if (rtm->rtm_family != AF_INET) {
                continue;
            }

            attr = (struct rtattr *)RTM_RTA(rtm);
            while (RTA_OK(attr, nh)) {
                if (attr->rta_type == RTA_DST || attr->rta_type == RTA_GATEWAY) {
                    char dst_str[INET_ADDRSTRLEN];
                    char gateway_str[INET_ADDRSTRLEN];

                    inet_ntop(AF_INET, RTA_DATA(attr), dst_str, sizeof(dst_str));
                    attr = RTA_NEXT(attr, nh);
                    inet_ntop(AF_INET, RTA_DATA(attr), gateway_str, sizeof(gateway_str));

                    printf("Destination: %s\tGateway: %s\n", dst_str, gateway_str);
                } else {
                    attr = RTA_NEXT(attr, nh);
                }
            }
        }
    }

    close(sock);
    return 0;
}
```

Эта программа создает сокет netlink для мониторинга изменений в таблице маршрутизации IPv4. При получении сообщения обновления маршрута программа выводит адреса назначения и шлюза на консоль.

```cpp
#include <iostream>

int main() {
    int N, speed, min_speed = 300, max_speed = 0, count_low_speed = 0;

    std::cin >> N;

    for (int i = 0; i < N; i++) {
        std::cin >> speed;

        if (speed < min_speed) {
            min_speed = speed;
        }

        if (speed > max_speed) {
            max_speed = speed;
        }

        if (speed <= 30) {
            count_low_speed++;
        }
    }

    std::cout << max_speed - min_speed << std::endl;
    std::cout << count_low_speed << std::endl;

    return 0;
}
```

Программа сначала считывает количество автомобилей N, затем в цикле считывает значения их скоростей. В процессе считывания находит минимальную и максимальную скорость, а также подсчитывает количество автомобилей, скорость которых не превышает 30 км/ч. Затем выводит разность максимальной и минимальной скоростей, а также количество автомобилей с низкой скоростью.

