function getDirections(vector) {
    return {
        left: { x: -vector.z, y: vector.y, z: vector.x },
        right: { x: vector.z, y: vector.y, z: -vector.x },
        forward: { x: -vector.x, y: vector.y, z: -vector.z },
        back: { x: vector.x, y: vector.y, z: vector.z }
    };
}

// Примеры использования
console.log(getDirections({ x: 0, y: 0, z: -1 })); // { left: {x:-1, y: 0, z:0}, right: {x:1, y: 0, z:0}, forward: {x:0, y: 0, z:-1}, back: {x:0, y: 0, z:1}, }
console.log(getDirections({ x: 0, y: 0, z: 1 })); // { left: {x:1, y: 0, z:0}, right: {x:-1, y: 0, z:0}, forward: {x:0, y: 0, z:1}, back: {x:0, y: 0, z:-1}, }
console.log(getDirections({ x: -1, y: 0, z: 0 })); // { left: {x:0, y: 0, z:1}, right: {x:0, y: 0, z:-1}, forward: {x:-1, y: 0, z:0}, back: {x:1, y: 0, z:0}, }
