#include <ESP8266WiFi.h>
#include <ESPAsyncTCP.h>
#include <AsyncTCP.h>
#include <ESPAsyncWebServer.h>

const char* ssid = "YourSSID";
const char* password = "YourPassword";

AsyncWebServer server(80);

int ledPin1 = D1; // светодиод #1 подключен к пину D1
int ledPin2 = D2; // светодиод #2 подключен к пину D2

unsigned long timer1 = 5000; // таймер #1 на 5 секунд
unsigned long timer2 = 10000; // таймер #2 на 10 секунд

unsigned long startTime1;
unsigned long startTime2;

void setup() {
  pinMode(ledPin1, OUTPUT);
  pinMode(ledPin2, OUTPUT);

  WiFi.begin(ssid, password);
  while (WiFi.status() != WL_CONNECTED) {
    delay(1000);
    Serial.println("Connecting to WiFi...");
  }

  Serial.println("Connected to WiFi");

  server.on("/", HTTP_GET, [](AsyncWebServerRequest *request){
    request->send(200, "text/html", "<h1>ESP8266 Async Web Server</h1>\
    <p><a href=\"/toggle1/on\"><button>Toggle LED #1 ON</button></a></p>\
    <p><a href=\"/toggle1/off\"><button>Toggle LED #1 OFF</button></a></p>\
    <p><a href=\"/toggle2\"><button>Toggle LED #2 and Start Timers</button></a></p>");
  });

  server.on("/toggle1/on", HTTP_GET, [](AsyncWebServerRequest *request){
    digitalWrite(ledPin1, HIGH);
    request->send(200, "text/plain", "LED #1 is ON");
  });

  server.on("/toggle1/off", HTTP_GET, [](AsyncWebServerRequest *request){
    digitalWrite(ledPin1, LOW);
    request->send(200, "text/plain", "LED #1 is OFF");
  });

  server.on("/toggle2", HTTP_GET, [](AsyncWebServerRequest *request){
    digitalWrite(ledPin2, HIGH);
    startTime1 = millis();
    startTime2 = millis();
    request->send(200, "text/plain", "LED #2 is ON and Timers started");
  });

  server.begin();
}

void loop() {
  unsigned long currentTime = millis();

  if (digitalRead(ledPin2) == HIGH) {
    if (currentTime - startTime1 >= timer1) {
      digitalWrite(ledPin2, LOW);
      startTime1 = currentTime;
    }

    if (currentTime - startTime2 >= timer2) {
      digitalWrite(ledPin2, LOW);
      startTime1 = currentTime;
      startTime2 = currentTime;
    }
  }
}

