import java.util.Arrays;
import java.util.Random;

public class Main {
    public static void main(String[] args) {
        int n = 100;
        int[] array = new int[n-1];

        // Заполнение массива уникальными числами от 1 до 100
        for (int i = 0; i < n-1; i++) {
            array[i] = i + 1;
        }

        // Перемешивание массива
        Random random = new Random();
        for (int i = 0; i < n-1; i++) {
            int randomIndex = random.nextInt(n-1);
            int temp = array[i];
            array[i] = array[randomIndex];
            array[randomIndex] = temp;
        }

        // Удаление одного случайного элемента из массива
        int missingNumber = array[random.nextInt(n-1)];
        int[] newArray = new int[n-1];
        int index = 0;
        for (int i = 0; i < n-1; i++) {
            if (array[i] != missingNumber) {
                newArray[index++] = array[i];
            }
        }

        // Вывод массива с пропущенным числом
        System.out.println(Arrays.toString(newArray));
    }
}
