```csharp
using System;
using System.Collections.Generic;
using System.Windows;
using System.Windows.Controls;
using System.Windows.Input;
using System.Windows.Media;
using System.Windows.Shapes;

namespace SimpleShooterGame
{
    public partial class MainWindow : Window
    {
        private const int gridSize = 8000;
        private const int playerSize = 50;
        private const int playerSpeed = 2;
        private const int enemySize = 10;
        private const int enemySpeed = 2;

        private Rectangle player;
        private Line playerDirection;
        private List<Rectangle> enemies = new List<Rectangle>();

        public MainWindow()
        {
            InitializeComponent();

            player = new Rectangle
            {
                Width = playerSize,
                Height = playerSize,
                Fill = Brushes.Green
            };

            playerDirection = new Line
            {
                X1 = playerSize / 2,
                Y1 = playerSize / 2,
                X2 = playerSize / 2,
                Y2 = playerSize / 2 - 30,
                Stroke = Brushes.Red,
                StrokeThickness = 2
            };

            Canvas.SetLeft(player, gridSize / 2 - playerSize / 2);
            Canvas.SetTop(player, gridSize / 2 - playerSize / 2);

            gameCanvas.Children.Add(player);
            gameCanvas.Children.Add(playerDirection);

            CompositionTarget.Rendering += GameLoop;
        }

        private void GameLoop(object sender, EventArgs e)
        {
            foreach (Rectangle enemy in enemies)
            {
                double angle = Math.Atan2(Canvas.GetTop(player) - Canvas.GetTop(enemy), Canvas.GetLeft(player) - Canvas.GetLeft(enemy));
                Canvas.SetLeft(enemy, Canvas.GetLeft(enemy) + Math.Cos(angle) * enemySpeed);
                Canvas.SetTop(enemy, Canvas.GetTop(enemy) + Math.Sin(angle) * enemySpeed);

                if (Math.Abs(Canvas.GetLeft(player) - Canvas.GetLeft(enemy)) < playerSize && Math.Abs(Canvas.GetTop(player) - Canvas.GetTop(enemy)) < playerSize)
                {
                    MessageBox.Show("GAME OVER");
                    RestartGame();
                    return;
                }
            }

            if (DateTime.Now.Second % 60 == 0)
            {
                Rectangle enemy = new Rectangle
                {
                    Width = enemySize,
                    Height = enemySize,
                    Fill = Brushes.Red
                };

                Canvas.SetLeft(enemy, new Random().Next(0, gridSize - enemySize));
                Canvas.SetTop(enemy, new Random().Next(0, gridSize - enemySize));

                enemies.Add(enemy);
                gameCanvas.Children.Add(enemy);
            }
        }

        private void RestartGame()
        {
            enemies.Clear();
            gameCanvas.Children.Clear();
            gameCanvas.Children.Add(player);
            gameCanvas.Children.Add(playerDirection);
        }

        private void Window_KeyDown(object sender, KeyEventArgs e)
        {
            if (e.Key == Key.Left)
            {
                playerDirection.RenderTransform = new RotateTransform(playerDirection.RenderTransform.Value.Angle - 90, playerSize / 2, playerSize / 2);
            }
            else if (e.Key == Key.Right)
            {
                playerDirection.RenderTransform = new RotateTransform(playerDirection.RenderTransform.Value.Angle + 90, playerSize / 2, playerSize / 2);
            }
            else if (e.Key == Key.Up)
            {
                Canvas.SetLeft(player, Canvas.GetLeft(player) + Math.Cos(playerDirection.RenderTransform.Value.Angle / 180 * Math.PI) * playerSpeed);
                Canvas.SetTop(player, Canvas.GetTop(player) + Math.Sin(playerDirection.RenderTransform.Value.Angle / 180 * Math.PI) * playerSpeed);
            }
        }
    }
}
```

Этот код создает простое окно WPF с игровым полем, героем, его направлением и красными врагами. Игра завершается при прикосновении врагов к герою, после чего начинается заново. Управление героем осуществляется с помощью клавиш стрелок.

