#include <iostream>
#include <cmath>

using namespace std;

double f(double x) {
    return x*x - 4;
}

void mullerMethod(double x0, double x1, double x2, double epsilon) {
    double h1 = x1 - x0;
    double h2 = x2 - x1;
    double d1 = (f(x1) - f(x0)) / h1;
    double d2 = (f(x2) - f(x1)) / h2;
    double a = (d2 - d1) / (h2 + h1);
    double b = a*h2 + d2;
    double c = f(x2);

    double D = sqrt(b*b - 4*a*c);
    double E = (b + (b >= 0 ? D : -D)) / -2*a;

    double x = x2 + E;

    if (abs(E) < epsilon) {
        cout << "Root found at x = " << x << endl;
        return;
    }

    mullerMethod(x1, x2, x, epsilon);
}

int main() {
    double x0 = 1.0;
    double x1 = 2.0;
    double x2 = 3.0;
    double epsilon = 0.0001;

    mullerMethod(x0, x1, x2, epsilon);

    return 0;
}

