напиши функцию на golang, которая считвыает этот конфиг из json: type Config struct {
Name string
Age int
}

answer:
package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
)

type Config struct {
	Name string `json:"name"`
	Age  int    `json:"age"`
}

func readConfig(filename string) (Config, error) {
	var config Config

	configFile, err := ioutil.ReadFile(filename)
	if err != nil {
		return config, err
	}

	err = json.Unmarshal(configFile, &config)
	if err != nil {
		return config, err
	}

	return config, nil
}

func main() {
	config, err := readConfig("config.json")
	if err != nil {
		fmt.Println("Error reading config file:", err)
		return
	}

	fmt.Println("Name:", config.Name)
	fmt.Println("Age:", config.Age)
}
```

```php
class FileStorage {
    private $eventHandlers = [];

    public function attachEvent($classMethodName, $callbackFunction) {
        $this->eventHandlers[$classMethodName] = $callbackFunction;
    }

    public function fireEvent($classMethodName) {
        if (isset($this->eventHandlers[$classMethodName])) {
            $callbackFunction = $this->eventHandlers[$classMethodName];
            $callbackFunction();
        } else {
            throw new Exception("No event handler found for method: $classMethodName");
        }
    }
}
``` 

Пример использования:

```php
$fileStorage = new FileStorage();

$fileStorage->attachEvent('someMethod', function() {
    echo "Custom callback function executed\n";
});

$fileStorage->fireEvent('someMethod'); // Output: Custom callback function executed
```
